Write-Host "Installing JavaScript/TypeScript Stack..." -ForegroundColor Cyan; $wingetPackages = @("OpenJS.NodeJS", "Git.Git", "Microsoft.VisualStudioCode", "Yarn.Yarn", "pnpm.pnpm", "Deno.Deno", "oven-sh.bun", "Microsoft.WindowsTerminal"); foreach($pkg in $wingetPackages) { winget install --id $pkg --accept-package-agreements --silent --force 2>$null }; $env:PATH = [System.Environment]::GetEnvironmentVariable("PATH", "Machine") + ";" + [System.Environment]::GetEnvironmentVariable("PATH", "User"); Start-Sleep 2; $jstsPackages = @("typescript", "ts-node", "tsx", "@swc/core", "@swc/cli", "esbuild", "webpack", "webpack-cli", "vite", "rollup", "parcel", "babel-cli", "@babel/core", "@babel/preset-env", "@babel/preset-typescript", "eslint", "@typescript-eslint/eslint-plugin", "@typescript-eslint/parser", "prettier", "jest", "@jest/cli", "mocha", "chai", "vitest", "nodemon", "ts-node-dev", "concurrently", "npm-run-all", "cross-env", "rimraf", "cpx", "onchange", "chokidar-cli", "typedoc", "jsdoc", "@types/node", "tsconfig-paths", "typescript-json-schema", "source-map-explorer", "madge", "depcheck", "npm-check-updates", "audit-ci", "husky", "lint-staged", "yargs", "commander", "inquirer", "chalk", "ora", "dotenv-cli", "pm2", "http-server", "live-server", "json-server", "cors"); foreach($npmPkg in $jstsPackages) { npm install -g $npmPkg --force --silent 2>$null }; New-Item -ItemType Directory -Path "$env:USERPROFILE\js-ts-dev" -Force -ErrorAction SilentlyContinue; '{"compilerOptions":{"target":"ES2020","module":"ESNext","lib":["ES2020"],"strict":true,"esModuleInterop":true,"skipLibCheck":true,"forceConsistentCasingInFileNames":true,"outDir":"./dist","rootDir":"./src","sourceMap":true,"declaration":true},"include":["src/**/*"],"exclude":["node_modules","dist"]}' | Out-File "$env:USERPROFILE\tsconfig.json" -Encoding UTF8; '{"semi":true,"singleQuote":true,"tabWidth":2,"trailingComma":"es5","printWidth":100}' | Out-File "$env:USERPROFILE\.prettierrc" -Encoding UTF8; Write-Host "JS/TS Stack Ready!" -ForegroundColor Green; if(Get-Command node -ErrorAction SilentlyContinue) { Write-Host "Node: $(node --version)" -ForegroundColor Green } else { Write-Host "Node: NOT FOUND" -ForegroundColor Red }; if(Get-Command tsc -ErrorAction SilentlyContinue) { Write-Host "TypeScript: $(tsc --version)" -ForegroundColor Green } else { Write-Host "TypeScript: NOT FOUND" -ForegroundColor Red }
